import { ensureInteractivityPluginLoaded } from "@tsparticles/plugin-interactivity";
import { AbsorbersInteractor } from "./AbsorbersInteractor.js";
import { getAbsorbersInstancesManager } from "./getAbsorbersInstancesManager.js";
export async function loadAbsorbersInteraction(engine) {
    engine.checkVersion("4.1.1");
    await engine.pluginManager.register(async (e) => {
        const pluginManager = e.pluginManager, instancesManager = await getAbsorbersInstancesManager(e);
        ensureInteractivityPluginLoaded(e);
        pluginManager.addInteractor?.("externalAbsorbers", container => {
            return Promise.resolve(new AbsorbersInteractor(container, instancesManager));
        });
    });
}
